  fortune_1_solution_3: { ko: ['마음이나 환경, 인간관계를 가볍게 정리하고 나면 다음 단계로 넘어가기 좋은 토대가 만들어져요.', '연말에 가까워질수록 올해 한 일이 정리되거나 인정받는 느낌이 들 수 있어요.'], en: ['Lightly organizing your mind, environment, and relationships creates a good base for the next step.', 'Toward year-end what you did may feel wrapped up or recognized.'], ja: ['心・環境・人間関係を軽く整理すると次のステップへ移りやすい土台ができる。', '年末に近づくほど今年やったことがまとまったり認められる感覚が。'] },
  fortune_1_relationship_5: { ko: ['지금은 "조금씩 정리되는" 느낌의 시기예요.', '중반에 작은 기회나 "덕분에 잘됐다"는 경험이 생길 수 있고, 내년을 위한 씨앗을 뿌려 두면 다음 해가 더 풍성해질 수 있어요.'], en: ['A phase of "things settling bit by bit."', 'In the middle you may have small opportunities; sowing seeds for next year can make the coming year richer.'], ja: ['今は「少しずつ整理される」感覚の時期。', '中盤に小さなチャンスや「おかげでうまくいった」経験があるかも。来年のための種をまいておくと翌年がより豊かになる。'] },
  fortune_1_cross_4: { ko: ['급하게 결과를 바라기보다 할 수 있는 일을 착실히 하는 것이 운을 키워요.', '중반에 작은 기회가 생길 수 있고, 연말에 가까워질수록 올해 한 일이 정리되거나 인정받는 느낌이 들 수 있어요.'], en: ['Steady effort builds luck more than hoping for quick results.', 'In the middle you may have small opportunities; toward year-end what you did may feel wrapped up or recognized.'], ja: ['結果を急がず、できることを着実にすることが運を育てる。', '中盤に小さなチャンスがあるかも。年末に近づくほど今年やったことがまとまったり認められる感覚が。'] },
