function buildAdditionalInsightsByQuestionAndSpread() {
  const out = {};
  Q.forEach((qId) => {
    out[qId] = {};
    S.forEach((sId) => {
      const key = `${qId}_${sId}`;
      const raw = ADDITIONAL_INSIGHTS_RAW[key];
      out[qId][sId] = raw || { ko: ['', ''], en: ['', ''], ja: ['', ''] };
    });
  });
  return out;
}

export const DIRECT_ANSWER_BY_QUESTION_AND_SPREAD = buildDirectAnswerByQuestionAndSpread();
export const ADDITIONAL_INSIGHTS_BY_QUESTION_AND_SPREAD = buildAdditionalInsightsByQuestionAndSpread();
